// ============ CHART GENERATORS ============
export function generatePriceHistory(days: number = 30) {
  const data = [];
  let price = 95000;
  const now = Date.now();
  for (let i = days; i >= 0; i--) {
    const change = (Math.random() - 0.48) * 2000;
    price = Math.max(price + change, 80000);
    data.push({
      date: new Date(now - i * 86400000).toLocaleDateString("zh-CN", { month: "short", day: "numeric" }),
      price: Math.round(price * 100) / 100,
      volume: Math.round(Math.random() * 30000000000),
    });
  }
  return data;
}

export function generatePortfolioHistory(days: number = 30) {
  const data = [];
  let value = 2200000;
  const now = Date.now();
  for (let i = days; i >= 0; i--) {
    const change = (Math.random() - 0.45) * 25000;
    value = Math.max(value + change, 2000000);
    data.push({
      date: new Date(now - i * 86400000).toLocaleDateString("zh-CN", { month: "short", day: "numeric" }),
      value: Math.round(value * 100) / 100,
      pnl: Math.round(change * 100) / 100,
    });
  }
  return data;
}

export function generate5YearHistory() {
  const data = [];
  let accuracy = 60;
  let sharpe = 0.5;
  let coins = 10;
  for (let y = 2021; y <= 2026; y++) {
    for (let m = 1; m <= (y === 2026 ? 2 : 12); m++) {
      accuracy = Math.min(95, accuracy + (Math.random() * 1.2 - 0.2));
      sharpe = Math.min(3, sharpe + (Math.random() * 0.06 - 0.01));
      coins = Math.min(450, coins + Math.floor(Math.random() * 8));
      data.push({
        date: `${y}-${String(m).padStart(2, "0")}`,
        accuracy: Math.round(accuracy * 10) / 10,
        sharpe: Math.round(sharpe * 100) / 100,
        coins,
        pnl: Math.round((Math.random() * 80000 - 15000) * 100) / 100,
      });
    }
  }
  return data;
}

// ============ FORMATTERS ============
export function formatNumber(num: number, decimals: number = 2): string {
  if (Math.abs(num) >= 1e9) return (num / 1e9).toFixed(decimals) + "B";
  if (Math.abs(num) >= 1e6) return (num / 1e6).toFixed(decimals) + "M";
  if (Math.abs(num) >= 1e3) return (num / 1e3).toFixed(decimals) + "K";
  return num.toFixed(decimals);
}

export function formatCurrency(num: number): string {
  return new Intl.NumberFormat("en-US", { style: "currency", currency: "USD" }).format(num);
}
